import React, { useState } from 'react';
import { 
  User, 
  FileEdit, 
  Calendar,
  ArrowLeft, 
  ArrowRight, 
  Check,
  Hash,
  Users,
  FileText
} from 'lucide-react';

const ClientForm = () => {
  const [currentSection, setCurrentSection] = useState(0);
  const [formData, setFormData] = useState({
    clientNumber: '',
    clientName: '',
    hearingDate: '',
    riders: '',
    additionalNotes: ''
  });

  const sections = [
    {
      title: 'Client Information',
      description: 'Enter basic client details',
      icon: User,
      color: 'bg-gradient-to-r from-blue-600 to-indigo-600'
    },
    {
      title: 'Case Details',
      description: 'Add case specific information',
      icon: FileEdit,
      color: 'bg-gradient-to-r from-purple-600 to-pink-600'
    },
    {
      title: 'Schedule',
      description: 'Set hearing dates',
      icon: Calendar,
      color: 'bg-gradient-to-r from-green-600 to-teal-600'
    }
  ];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleNextSection = () => {
    if (currentSection < sections.length - 1) {
      setCurrentSection(curr => curr + 1);
    }
  };

  const handlePreviousSection = () => {
    if (currentSection > 0) {
      setCurrentSection(curr => curr - 1);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  const renderClientInfoSection = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Client A#</label>
          <div className="relative group">
            <Hash className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="text"
              name="clientNumber"
              value={formData.clientNumber}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm shadow-sm
                       transition-all duration-200 
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500 dark:hover:border-blue-400"
              placeholder="Enter client number"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Client Name</label>
          <div className="relative group">
            <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="text"
              name="clientName"
              value={formData.clientName}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm shadow-sm
                       transition-all duration-200
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500 dark:hover:border-blue-400"
              placeholder="Enter client name"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Hearing Date</label>
          <div className="relative group">
            <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="date"
              name="hearingDate"
              value={formData.hearingDate}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm shadow-sm
                       transition-all duration-200
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500 dark:hover:border-blue-400"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Rider(s)</label>
          <div className="relative group">
            <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="text"
              name="riders"
              value={formData.riders}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm shadow-sm
                       transition-all duration-200
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500 dark:hover:border-blue-400"
              placeholder="Enter riders"
            />
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium text-gray-700 dark:text-gray-200">Additional Notes</label>
        <div className="relative group">
          <FileText className="absolute left-3 top-3 text-gray-400 group-hover:text-blue-500 transition-colors" />
          <textarea
            name="additionalNotes"
            value={formData.additionalNotes}
            onChange={handleInputChange}
            rows="4"
            className="pl-10 w-full rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-3 text-sm shadow-sm
                     transition-all duration-200
                     focus:ring-2 focus:ring-blue-500 focus:border-transparent
                     hover:border-blue-500 dark:hover:border-blue-400"
            placeholder="Enter any additional notes"
          />
        </div>
      </div>
    </div>
  );

  const renderCurrentSection = () => {
    switch (currentSection) {
      case 0:
        return renderClientInfoSection();
      case 1:
      case 2:
        return (
          <div className="p-8 text-center text-gray-500 dark:text-gray-400 animate-fadeIn">
            <div className="mb-4">
              <FileEdit className="h-16 w-16 mx-auto text-gray-400 dark:text-gray-500" />
            </div>
            <h3 className="text-xl font-semibold mb-2">Coming Soon</h3>
            <p>This section is under development</p>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">Client Information System</h1>
          <p className="text-gray-600 dark:text-gray-400">Manage your client information efficiently</p>
        </div>

        {/* Section Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          {sections.map((section, index) => {
            const Icon = section.icon;
            return (
              <div
                key={index}
                onClick={() => setCurrentSection(index)}
                className={`relative cursor-pointer rounded-xl p-6 ${
                  index === currentSection 
                    ? section.color 
                    : 'bg-white dark:bg-gray-800'
                } transform transition-all duration-300 hover:scale-105 hover:shadow-xl shadow-lg`}
              >
                <div className="flex items-center space-x-4">
                  <div className={`p-3 rounded-lg ${
                    index === currentSection 
                      ? 'bg-white/20' 
                      : 'bg-gray-100 dark:bg-gray-700'
                  }`}>
                    <Icon className={`h-6 w-6 ${
                      index === currentSection 
                        ? 'text-white' 
                        : 'text-gray-500 dark:text-gray-400'
                    }`} />
                  </div>
                  <div>
                    <h3 className={`font-semibold ${
                      index === currentSection 
                        ? 'text-white' 
                        : 'text-gray-900 dark:text-gray-100'
                    }`}>
                      {section.title}
                    </h3>
                    <p className={`text-sm ${
                      index === currentSection 
                        ? 'text-white/80' 
                        : 'text-gray-500 dark:text-gray-400'
                    }`}>
                      {section.description}
                    </p>
                  </div>
                </div>
                {index === currentSection && (
                  <div className="absolute -top-2 -right-2">
                    <div className="bg-white dark:bg-blue-600 rounded-full p-1.5 shadow-lg">
                      <Check className="h-4 w-4 text-blue-600 dark:text-white" />
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Form Content */}
        <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg p-8 mb-8 border border-gray-200 dark:border-gray-700">
          <form onSubmit={handleSubmit}>
            {renderCurrentSection()}
          </form>
        </div>

        {/* Navigation Buttons */}
        <div className="flex justify-between">
          <button
            type="button"
            onClick={handlePreviousSection}
            disabled={currentSection === 0}
            className={`flex items-center px-6 py-3 rounded-lg transition-all ${
              currentSection === 0
                ? 'bg-gray-100 dark:bg-gray-800 text-gray-400 cursor-not-allowed'
                : 'bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-300 shadow-lg hover:shadow-xl'
            }`}
          >
            <ArrowLeft className="h-5 w-5 mr-2" />
            Previous
          </button>
          
          {currentSection === sections.length - 1 ? (
            <button
              type="submit"
              className="flex items-center px-8 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg hover:from-blue-700 hover:to-indigo-700 transition-all shadow-lg hover:shadow-xl"
            >
              <Check className="h-5 w-5 mr-2" />
              Submit Form
            </button>
          ) : (
            <button
              type="button"
              onClick={handleNextSection}
              className="flex items-center px-6 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg hover:from-blue-700 hover:to-indigo-700 transition-all shadow-lg hover:shadow-xl"
            >
              Next
              <ArrowRight className="h-5 w-5 ml-2" />
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default ClientForm;
